import React, { useState, useEffect, useMemo, useCallback } from 'react';
import InterviewControls from './components/InterviewControls.jsx';
import InterviewSession from './components/InterviewSession.jsx';
import FeedbackPanel from './components/FeedbackPanel.jsx';

function InterviewSimulator() {
  // Widget storage for persisting session data
  const [interviewType, setInterviewType] = useStorage('interview-type', 'Behavioral');
  const [role, setRole] = useStorage('role', 'SWE');
  const [level, setLevel] = useStorage('level', 'Mid-Level');
  const [companyName, setCompanyName] = useStorage('company-name', '');
  const [jobDescription, setJobDescription] = useStorage('job-description', '');
  const [resumeText, setResumeText] = useStorage('resume-text', '');
  const [currentQuestion, setCurrentQuestion] = useStorage('current-question', '');
  const [userAnswer, setUserAnswer] = useStorage('user-answer', '');
  const [feedback, setFeedback] = useStorage('feedback', null);
  const [sessionActive, setSessionActive] = useStorage('session-active', false);
  const [isLoading, setIsLoading] = useStorage('is-loading', false);
  const [questionHistory, setQuestionHistory] = useStorage('question-history', []);
  const [hint, setHint] = useStorage('hint', '');

  // Global storage for saved questions/answers library
  const [savedQuestions, setSavedQuestions] = useGlobalStorage('interview.questions.library', []);

  // Start interview session
  const handleStartSession = useCallback(async () => {
    setIsLoading(true);
    setSessionActive(true);
    setFeedback(null);
    setUserAnswer('');

    try {
      let prompt;

      // Resume Digging mode - analyze resume and ask specific questions
      if (interviewType === 'Resume Digging' && resumeText) {
        prompt = `You are an expert interviewer conducting a resume-based interview. Analyze the following resume and generate ONE specific, probing question about the candidate's experience.

Resume:
${resumeText.substring(0, 3000)}${resumeText.length > 3000 ? '...' : ''}

Role: ${level} ${role}`;

        if (companyName) {
          prompt += `
Company: ${companyName}`;
        }

        prompt += `

Generate a specific question that:
1. References a concrete project, role, or achievement from their resume
2. Asks them to elaborate on technical decisions, challenges, or impact
3. Is appropriate for a ${level} candidate
4. Probes deeper than surface-level descriptions

Return ONLY the question, no additional text.`;
      } else {
        // Standard interview question generation
        prompt = `Generate a realistic ${interviewType} interview question for a ${level} ${role} position`;

        if (companyName) {
          prompt += ` at ${companyName}`;
        }

        prompt += '.';

        if (jobDescription) {
          prompt += ` Job description: ${jobDescription}`;
        }

        if (companyName && !jobDescription) {
          prompt += ` Consider ${companyName}'s industry, culture, and typical interview style.`;
        }

        // Add level-specific guidance
        prompt += ` The question should be appropriate for a ${level} candidate`;

        if (level === 'Intern') {
          prompt += ' - focus on foundational knowledge, learning ability, and potential rather than extensive experience.';
        } else if (level === 'Entry-Level / New Grad') {
          prompt += ' - focus on recent education, projects, and basic professional skills.';
        } else if (level === 'Mid-Level') {
          prompt += ' - expect 2-5 years of experience, proven track record, and independent problem-solving.';
        } else if (level === 'Senior') {
          prompt += ' - expect deep expertise, leadership, architectural decisions, and mentorship experience.';
        } else if (level === 'Staff / Principal') {
          prompt += ' - expect technical leadership across teams, system design at scale, and strategic impact.';
        } else if (level === 'Director / VP') {
          prompt += ' - focus on organizational leadership, strategy, cross-functional collaboration, and business impact.';
        }

        prompt += ' Return only the question, no additional text.';
      }

      const question = await miyagiAPI('generate-text', {
        prompt,
        provider: 'openai',
        model: 'gpt-4o-mini',
        max_tokens: 200,
        temperature: 0.8
      });

      setCurrentQuestion(question);
      setQuestionHistory(prev => [...prev, { question, timestamp: new Date().toISOString() }]);
    } catch (error) {
      console.error('Error generating question:', error);
      setCurrentQuestion('Error generating question. Please try again.');
    } finally {
      setIsLoading(false);
    }
  }, [interviewType, role, level, companyName, jobDescription, resumeText]);

  // Generate another question
  const handleGenerateAnother = useCallback(async () => {
    setIsLoading(true);
    setFeedback(null);
    setUserAnswer('');
    setHint('');

    try {
      const previousQuestions = questionHistory.map(q => q.question).join('\n');

      let prompt;

      // Resume Digging mode
      if (interviewType === 'Resume Digging' && resumeText) {
        prompt = `You are an expert interviewer conducting a resume-based interview. Analyze the following resume and generate ONE different specific question about the candidate's experience.

Resume:
${resumeText.substring(0, 3000)}${resumeText.length > 3000 ? '...' : ''}

Role: ${level} ${role}`;

        if (companyName) {
          prompt += `
Company: ${companyName}`;
        }

        prompt += `

Previously asked questions:
${previousQuestions}

Generate a DIFFERENT specific question that:
1. References a concrete project, role, or achievement from their resume (different from previous questions)
2. Asks them to elaborate on technical decisions, challenges, or impact
3. Is appropriate for a ${level} candidate
4. Probes deeper than surface-level descriptions

Return ONLY the question, no additional text.`;
      } else {
        // Standard interview question generation
        prompt = `Generate a different ${interviewType} interview question for a ${level} ${role} position`;

        if (companyName) {
          prompt += ` at ${companyName}`;
        }

        prompt += '.';

        if (jobDescription) {
          prompt += ` Job description: ${jobDescription}`;
        }

        if (companyName && !jobDescription) {
          prompt += ` Consider ${companyName}'s industry, culture, and typical interview style.`;
        }

        // Add level-specific guidance
        prompt += ` The question should be appropriate for a ${level} candidate`;

        if (level === 'Intern') {
          prompt += ' - focus on foundational knowledge, learning ability, and potential rather than extensive experience.';
        } else if (level === 'Entry-Level / New Grad') {
          prompt += ' - focus on recent education, projects, and basic professional skills.';
        } else if (level === 'Mid-Level') {
          prompt += ' - expect 2-5 years of experience, proven track record, and independent problem-solving.';
        } else if (level === 'Senior') {
          prompt += ' - expect deep expertise, leadership, architectural decisions, and mentorship experience.';
        } else if (level === 'Staff / Principal') {
          prompt += ' - expect technical leadership across teams, system design at scale, and strategic impact.';
        } else if (level === 'Director / VP') {
          prompt += ' - focus on organizational leadership, strategy, cross-functional collaboration, and business impact.';
        }

        prompt += ` Avoid these questions:\n${previousQuestions}\n\nReturn only the new question, no additional text.`;
      }

      const question = await miyagiAPI('generate-text', {
        prompt,
        provider: 'openai',
        model: 'gpt-4o-mini',
        max_tokens: 200,
        temperature: 0.9
      });

      setCurrentQuestion(question);
      setQuestionHistory(prev => [...prev, { question, timestamp: new Date().toISOString() }]);
    } catch (error) {
      console.error('Error generating question:', error);
    } finally {
      setIsLoading(false);
    }
  }, [interviewType, role, level, companyName, jobDescription, resumeText, questionHistory]);

  // Submit answer for feedback
  const handleSubmitAnswer = useCallback(async () => {
    if (!userAnswer.trim()) return;

    setIsLoading(true);

    try {
      const systemPrompt = `You are an expert interview coach. Evaluate the candidate's answer and provide:
1. A numerical score from 1-10
2. 2-3 strengths (bullet points)
3. 2-3 areas for improvement (bullet points)
4. An improved version of the answer using STAR format (Situation, Task, Action, Result)
5. A relevant follow-up question

IMPORTANT: Return ONLY valid JSON, no markdown formatting, no code blocks. Use this exact structure:
{"score": number, "strengths": ["string"], "improvements": ["string"], "improvedAnswer": "string", "followUp": "string"}`;

      let prompt = `Interview Type: ${interviewType}
Role: ${role}
Level: ${level}`;

      if (companyName) {
        prompt += `
Company: ${companyName}`;
      }

      prompt += `
Question: ${currentQuestion}
Candidate's Answer: ${userAnswer}

Evaluate this answer thoroughly for a ${level} candidate`;

      if (companyName) {
        prompt += `, considering what ${companyName} would be looking for`;
      }

      prompt += '. Adjust expectations based on the seniority level';

      if (level === 'Intern' || level === 'Entry-Level / New Grad') {
        prompt += ' - be encouraging but provide constructive feedback on fundamentals.';
      } else if (level === 'Senior' || level === 'Staff / Principal' || level === 'Director / VP') {
        prompt += ' - expect depth, leadership examples, and strategic thinking.';
      } else {
        prompt += '.';
      }

      const feedbackText = await miyagiAPI('generate-text', {
        prompt,
        system_prompt: systemPrompt,
        provider: 'openai',
        model: 'gpt-4o',
        max_tokens: 1000,
        temperature: 0.7
      });

      // Parse JSON response - handle markdown code blocks
      let parsedFeedback;
      try {
        // Remove markdown code blocks if present
        let cleanedText = feedbackText.trim();
        if (cleanedText.startsWith('```json')) {
          cleanedText = cleanedText.replace(/^```json\s*/, '').replace(/\s*```$/, '');
        } else if (cleanedText.startsWith('```')) {
          cleanedText = cleanedText.replace(/^```\s*/, '').replace(/\s*```$/, '');
        }
        parsedFeedback = JSON.parse(cleanedText);
      } catch (e) {
        console.error('JSON parse error:', e, 'Raw text:', feedbackText);
        // Fallback if JSON parsing fails
        parsedFeedback = {
          score: 7,
          strengths: ['Good attempt at answering'],
          improvements: ['Could provide more specific details'],
          improvedAnswer: feedbackText,
          followUp: 'Can you elaborate on the outcome?'
        };
      }

      setFeedback(parsedFeedback);
    } catch (error) {
      console.error('Error getting feedback:', error);
      setFeedback({
        score: 0,
        strengths: [],
        improvements: ['Error generating feedback'],
        improvedAnswer: '',
        followUp: ''
      });
    } finally {
      setIsLoading(false);
    }
  }, [userAnswer, currentQuestion, interviewType, role, level, companyName]);

  // Show hint/STAR structure
  const handleShowHint = useCallback(async () => {
    setIsLoading(true);

    try {
      const prompt = `For this ${interviewType} interview question: "${currentQuestion}"

Provide a helpful hint using the STAR framework:
- Situation: What context to set
- Task: What challenge/goal to describe
- Action: What specific actions to mention
- Result: What outcomes to highlight

Keep it brief and actionable.`;

      const hintText = await miyagiAPI('generate-text', {
        prompt,
        provider: 'openai',
        model: 'gpt-4o-mini',
        max_tokens: 300,
        temperature: 0.7
      });

      setHint(hintText);
    } catch (error) {
      console.error('Error generating hint:', error);
      setHint('Error generating hint. Please try again.');
    } finally {
      setIsLoading(false);
    }
  }, [currentQuestion, interviewType]);

  // Save answer to library (saves polished version)
  const handleSaveAnswer = useCallback(() => {
    if (!feedback) {
      alert('Please submit your answer first to get feedback before saving!');
      return;
    }

    const newSavedQuestion = {
      id: Date.now(),
      question: currentQuestion,
      originalAnswer: userAnswer,
      polishedAnswer: feedback.improvedAnswer || userAnswer,
      score: feedback.score || 0,
      interviewType,
      role,
      tags: [], // User can add tags in Question Library
      timestamp: new Date().toISOString(),
      status: 'review', // 'review' or 'mastered'
      notes: '',
      strengths: feedback.strengths || [],
      improvements: feedback.improvements || []
    };

    setSavedQuestions(prev => [newSavedQuestion, ...prev]);
    alert('? Question saved to library with polished answer!');
  }, [currentQuestion, userAnswer, interviewType, role, feedback]);

  return (
    <div style={{
      width: '100%',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      backgroundColor: '#f8f9fa',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
      overflow: 'hidden'
    }}>
      <div style={{
        padding: '20px 24px',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
        borderBottom: '3px solid #5568d3',
        boxShadow: '0 4px 12px rgba(102, 126, 234, 0.3)'
      }}>
        <h2 style={{ 
          margin: 0, 
          fontSize: '24px', 
          color: '#fff', 
          fontWeight: 700,
          display: 'flex',
          alignItems: 'center',
          gap: '12px'
        }}>
          <span style={{ fontSize: '28px' }}>{'\u{1F3AF}'}</span>
          <span>Smart Interview Simulator</span>
        </h2>
        <p style={{ 
          margin: '8px 0 0 40px', 
          fontSize: '13px', 
          color: 'rgba(255,255,255,0.9)',
          fontWeight: 400
        }}>
          Practice interviews with AI-powered feedback
        </p>
      </div>

      <div style={{
        flex: 1,
        overflow: 'auto',
        padding: '20px'
      }}>
        {!sessionActive ? (
          <InterviewControls
            interviewType={interviewType}
            setInterviewType={setInterviewType}
            role={role}
            setRole={setRole}
            level={level}
            setLevel={setLevel}
            companyName={companyName}
            setCompanyName={setCompanyName}
            jobDescription={jobDescription}
            setJobDescription={setJobDescription}
            resumeText={resumeText}
            setResumeText={setResumeText}
            onStartSession={handleStartSession}
            isLoading={isLoading}
          />
        ) : (
          <>
            <InterviewSession
              currentQuestion={currentQuestion}
              userAnswer={userAnswer}
              setUserAnswer={setUserAnswer}
              onSubmitAnswer={handleSubmitAnswer}
              onGenerateAnother={handleGenerateAnother}
              onShowHint={handleShowHint}
              onSaveAnswer={handleSaveAnswer}
              isLoading={isLoading}
              hasAnswer={userAnswer.trim().length > 0}
              hint={hint}
              onClearHint={() => setHint('')}
            />

            {feedback && (
              <FeedbackPanel feedback={feedback} />
            )}
          </>
        )}
      </div>

      {sessionActive && (
        <div style={{
          padding: '12px 20px',
          backgroundColor: '#fff',
          borderTop: '1px solid #e9ecef',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <button
            onClick={() => {
              setSessionActive(false);
              setCurrentQuestion('');
              setUserAnswer('');
              setFeedback(null);
              setHint('');
            }}
            style={{
              padding: '8px 16px',
              backgroundColor: '#6c757d',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              cursor: 'pointer',
              fontSize: '14px',
              fontWeight: 500
            }}
          >
            End Session
          </button>
          <div style={{ fontSize: '12px', color: '#6c757d' }}>
            Questions asked: {questionHistory.length}
          </div>
        </div>
      )}
    </div>
  );
}

export default InterviewSimulator;

sources.components/FeedbackPanel.jsx:
import React from 'react';

function FeedbackPanel({ feedback }) {
  if (!feedback) return null;

  const getScoreColor = (score) => {
    if (score >= 8) return '#28a745';
    if (score >= 6) return '#ffc107';
    return '#dc3545';
  };

  const getScoreLabel = (score) => {
    if (score >= 9) return 'Excellent';
    if (score >= 8) return 'Very Good';
    if (score >= 7) return 'Good';
    if (score >= 6) return 'Fair';
    if (score >= 5) return 'Needs Work';
    return 'Poor';
  };

  return (
    <div style={{ maxWidth: '900px', margin: '0 auto', marginTop: '20px' }}>
      <div style={{
        backgroundColor: 'white',
        padding: '24px',
        borderRadius: '12px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
        border: '2px solid #28a745'
      }}>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          marginBottom: '20px'
        }}>
          <span style={{ fontSize: '24px', marginRight: '12px' }}>📊</span>
          <h3 style={{ margin: 0, color: '#28a745', fontSize: '18px', fontWeight: 600 }}>
            AI Feedback
          </h3>
        </div>

        {/* Score Section */}
        <div style={{
          backgroundColor: '#f8f9fa',
          padding: '20px',
          borderRadius: '8px',
          marginBottom: '20px',
          textAlign: 'center'
        }}>
          <div style={{ fontSize: '14px', color: '#6c757d', marginBottom: '8px' }}>
            Overall Score
          </div>
          <div style={{
            fontSize: '48px',
            fontWeight: 'bold',
            color: getScoreColor(feedback.score),
            marginBottom: '8px'
          }}>
            {feedback.score}/10
          </div>
          <div style={{
            fontSize: '16px',
            fontWeight: 600,
            color: getScoreColor(feedback.score)
          }}>
            {getScoreLabel(feedback.score)}
          </div>
        </div>

        {/* Strengths */}
        {feedback.strengths && feedback.strengths.length > 0 && (
          <div style={{ marginBottom: '20px' }}>
            <h4 style={{
              fontSize: '16px',
              fontWeight: 600,
              color: '#28a745',
              marginBottom: '12px',
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>✅</span>
              <span>Strengths</span>
            </h4>
            <ul style={{
              margin: 0,
              paddingLeft: '24px',
              listStyle: 'none'
            }}>
              {feedback.strengths.map((strength, idx) => (
                <li key={idx} style={{
                  fontSize: '14px',
                  lineHeight: '1.6',
                  color: '#212529',
                  marginBottom: '8px',
                  position: 'relative'
                }}>
                  <span style={{
                    position: 'absolute',
                    left: '-20px',
                    color: '#28a745'
                  }}>
                    •
                  </span>
                  {strength}
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Improvements */}
        {feedback.improvements && feedback.improvements.length > 0 && (
          <div style={{ marginBottom: '20px' }}>
            <h4 style={{
              fontSize: '16px',
              fontWeight: 600,
              color: '#dc3545',
              marginBottom: '12px',
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>🛠️</span>
              <span>Areas for Improvement</span>
            </h4>
            <ul style={{
              margin: 0,
              paddingLeft: '24px',
              listStyle: 'none'
            }}>
              {feedback.improvements.map((improvement, idx) => (
                <li key={idx} style={{
                  fontSize: '14px',
                  lineHeight: '1.6',
                  color: '#212529',
                  marginBottom: '8px',
                  position: 'relative'
                }}>
                  <span style={{
                    position: 'absolute',
                    left: '-20px',
                    color: '#dc3545'
                  }}>
                    •
                  </span>
                  {improvement}
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* Improved Answer */}
        {feedback.improvedAnswer && (
          <div style={{ marginBottom: '20px' }}>
            <h4 style={{
              fontSize: '16px',
              fontWeight: 600,
              color: '#007bff',
              marginBottom: '12px',
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>⭐</span>
              <span>Improved Version (STAR Format)</span>
            </h4>
            <div style={{
              backgroundColor: '#e7f3ff',
              padding: '16px',
              borderRadius: '8px',
              fontSize: '14px',
              lineHeight: '1.6',
              color: '#212529',
              border: '1px solid #b3d9ff',
              whiteSpace: 'pre-wrap'
            }}>
              {feedback.improvedAnswer}
            </div>
          </div>
        )}

        {/* Follow-up Question */}
        {feedback.followUp && (
          <div style={{
            backgroundColor: '#fff3cd',
            padding: '16px',
            borderRadius: '8px',
            border: '1px solid #ffc107'
          }}>
            <h4 style={{
              fontSize: '14px',
              fontWeight: 600,
              color: '#856404',
              marginBottom: '8px',
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>❓</span>
              <span>Follow-up Question</span>
            </h4>
            <div style={{
              fontSize: '14px',
              lineHeight: '1.6',
              color: '#212529'
            }}>
              {feedback.followUp}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default FeedbackPanel;

sources.components/InterviewControls.jsx:
import React from 'react';

const INTERVIEW_TYPES = [
  'Behavioral',
  'Technical Explanation',
  'Product Sense (PM)',
  'Research / Academic',
  'Culture Fit / Small Talk',
  'Salary Negotiation',
  'Resume Digging'
];

const COMMON_ROLES = [
  'SWE',
  'MLE',
  'DS',
  'PM',
  'Researcher',
  'Designer',
  'Engineering Manager',
  'Product Designer',
  'Data Engineer',
  'DevOps Engineer'
];

const EXPERIENCE_LEVELS = [
  'Intern',
  'Entry-Level / New Grad',
  'Mid-Level',
  'Senior',
  'Staff / Principal',
  'Director / VP'
];

function InterviewControls({
  interviewType,
  setInterviewType,
  role,
  setRole,
  level,
  setLevel,
  companyName,
  setCompanyName,
  jobDescription,
  setJobDescription,
  resumeText,
  setResumeText,
  onStartSession,
  isLoading
}) {
  // Check if current role is a custom role (not in predefined list)
  const isRoleCustom = !COMMON_ROLES.includes(role);

  const [customRole, setCustomRole] = React.useState('');
  const [useCustomRole, setUseCustomRole] = React.useState(isRoleCustom);
  const [uploadingResume, setUploadingResume] = React.useState(false);
  const [resumeFileName, setResumeFileName] = React.useState('');

  const handleRoleChange = (value) => {
    if (value === 'custom') {
      setUseCustomRole(true);
      setCustomRole('');
    } else {
      setUseCustomRole(false);
      setRole(value);
    }
  };

  // Handle resume file upload
  const handleResumeUpload = async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    // Check file type
    const validTypes = ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
    if (!validTypes.includes(file.type)) {
      alert('Please upload a PDF or Word document (.pdf, .doc, .docx)');
      return;
    }

    // Check file size (max 10MB)
    if (file.size > 10 * 1024 * 1024) {
      alert('File size must be less than 10MB');
      return;
    }

    setUploadingResume(true);
    setResumeFileName(file.name);

    try {
      // Convert file to base64
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
          const base64 = e.target.result.split(',')[1]; // Remove data:*/*;base64, prefix

          // Extract text from document
          const result = await miyagiAPI('extract-document-text', {
            file: base64,
            filename: file.name
          });

          if (result.success && result.text) {
            setResumeText(result.text);
            alert(`✅ Resume uploaded successfully! Extracted ${result.text.length} characters.`);
          } else {
            throw new Error('Failed to extract text from document');
          }
        } catch (error) {
          console.error('Error extracting text:', error);
          alert('Error processing resume. Please try again.');
          setResumeText('');
          setResumeFileName('');
        } finally {
          setUploadingResume(false);
        }
      };

      reader.onerror = () => {
        alert('Error reading file. Please try again.');
        setUploadingResume(false);
        setResumeFileName('');
      };

      reader.readAsDataURL(file);
    } catch (error) {
      console.error('Error uploading resume:', error);
      alert('Error uploading resume. Please try again.');
      setUploadingResume(false);
      setResumeFileName('');
    }
  };

  return (
    <div style={{ maxWidth: '800px', margin: '0 auto' }}>
      <div style={{
        backgroundColor: 'white',
        padding: '32px',
        borderRadius: '16px',
        boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
        border: '1px solid #e9ecef'
      }}>
        <div style={{ 
          marginBottom: '32px',
          textAlign: 'center'
        }}>
          <h3 style={{ 
            marginTop: 0, 
            marginBottom: '8px', 
            color: '#212529', 
            fontSize: '24px',
            fontWeight: 700
          }}>
            Setup Your Interview
          </h3>
          <p style={{ 
            margin: 0, 
            color: '#6c757d', 
            fontSize: '14px' 
          }}>
            Configure your practice session and get AI-powered feedback
          </p>
        </div>

        {/* Interview Type */}
        <div style={{ marginBottom: '24px' }}>
          <label style={{
            display: 'block',
            marginBottom: '10px',
            fontWeight: 600,
            fontSize: '15px',
            color: '#495057'
          }}>
            <span style={{ marginRight: '8px' }}>📋</span>
            Interview Type
          </label>
          <select
            value={interviewType}
            onChange={(e) => setInterviewType(e.target.value)}
            style={{
              width: '100%',
              padding: '12px 14px',
              fontSize: '15px',
              border: '2px solid #e9ecef',
              borderRadius: '10px',
              backgroundColor: 'white',
              cursor: 'pointer',
              transition: 'all 0.2s',
              outline: 'none'
            }}
            onFocus={(e) => e.target.style.borderColor = '#667eea'}
            onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
          >
            {INTERVIEW_TYPES.map(type => (
              <option key={type} value={type}>{type}</option>
            ))}
          </select>
        </div>

        {/* Role Selection */}
        <div style={{ marginBottom: '24px' }}>
          <label style={{
            display: 'block',
            marginBottom: '10px',
            fontWeight: 600,
            fontSize: '15px',
            color: '#495057'
          }}>
            <span style={{ marginRight: '8px' }}>👤</span>
            Role
          </label>
          {!useCustomRole ? (
            <div>
              <select
                value={isRoleCustom ? 'custom' : role}
                onChange={(e) => handleRoleChange(e.target.value)}
                style={{
                  width: '100%',
                  padding: '12px 14px',
                  fontSize: '15px',
                  border: '2px solid #e9ecef',
                  borderRadius: '10px',
                  backgroundColor: 'white',
                  cursor: 'pointer',
                  transition: 'all 0.2s',
                  outline: 'none'
                }}
                onFocus={(e) => e.target.style.borderColor = '#667eea'}
                onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
              >
                {COMMON_ROLES.map(r => (
                  <option key={r} value={r}>{r}</option>
                ))}
                <option value="custom">✏️ Custom Role...</option>
              </select>
              {isRoleCustom && (
                <div style={{
                  marginTop: '10px',
                  padding: '10px 14px',
                  backgroundColor: '#f8f9fa',
                  borderRadius: '8px',
                  border: '1px solid #e9ecef',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center'
                }}>
                  <div>
                    <span style={{ fontSize: '13px', color: '#6c757d', marginRight: '8px' }}>
                      Custom role:
                    </span>
                    <span style={{ fontSize: '15px', color: '#212529', fontWeight: 600 }}>
                      {role}
                    </span>
                  </div>
                  <button
                    onClick={() => {
                      setCustomRole(role);
                      setUseCustomRole(true);
                    }}
                    style={{
                      padding: '6px 12px',
                      backgroundColor: '#667eea',
                      color: 'white',
                      border: 'none',
                      borderRadius: '6px',
                      cursor: 'pointer',
                      fontSize: '13px',
                      fontWeight: 500
                    }}
                  >
                    Edit
                  </button>
                </div>
              )}
            </div>
          ) : (
            <div style={{ display: 'flex', gap: '10px' }}>
              <input
                type="text"
                value={customRole}
                onChange={(e) => setCustomRole(e.target.value)}
                placeholder="Enter custom role..."
                style={{
                  flex: 1,
                  padding: '12px 14px',
                  fontSize: '15px',
                  border: '2px solid #667eea',
                  borderRadius: '10px',
                  outline: 'none'
                }}
                autoFocus
              />
              <button
                onClick={() => {
                  if (customRole.trim()) {
                    setRole(customRole.trim());
                    setUseCustomRole(false);
                    setCustomRole('');
                  }
                }}
                style={{
                  padding: '12px 20px',
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  cursor: 'pointer',
                  fontSize: '15px',
                  fontWeight: 600,
                  transition: 'transform 0.2s'
                }}
                onMouseEnter={(e) => e.target.style.transform = 'scale(1.05)'}
                onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
              >
                Set
              </button>
              <button
                onClick={() => {
                  setUseCustomRole(false);
                  setCustomRole('');
                  // If current role is custom, reset to default
                  if (isRoleCustom) {
                    setRole('SWE');
                  }
                }}
                style={{
                  padding: '12px 20px',
                  backgroundColor: '#6c757d',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  cursor: 'pointer',
                  fontSize: '15px',
                  fontWeight: 600
                }}
              >
                Cancel
              </button>
            </div>
          )}
        </div>

        {/* Experience Level */}
        <div style={{ marginBottom: '24px' }}>
          <label style={{
            display: 'block',
            marginBottom: '10px',
            fontWeight: 600,
            fontSize: '15px',
            color: '#495057'
          }}>
            <span style={{ marginRight: '8px' }}>📊</span>
            Experience Level
          </label>
          <select
            value={level}
            onChange={(e) => setLevel(e.target.value)}
            style={{
              width: '100%',
              padding: '12px 14px',
              fontSize: '15px',
              border: '2px solid #e9ecef',
              borderRadius: '10px',
              backgroundColor: 'white',
              cursor: 'pointer',
              transition: 'all 0.2s',
              outline: 'none'
            }}
            onFocus={(e) => e.target.style.borderColor = '#667eea'}
            onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
          >
            {EXPERIENCE_LEVELS.map(lvl => (
              <option key={lvl} value={lvl}>{lvl}</option>
            ))}
          </select>
          <div style={{ 
            fontSize: '13px', 
            color: '#6c757d', 
            marginTop: '8px',
            display: 'flex',
            alignItems: 'center',
            gap: '6px'
          }}>
            <span>💡</span>
            <span>Questions will be adjusted for appropriate difficulty and expectations</span>
          </div>
        </div>

        {/* Company Name */}
        <div style={{ marginBottom: '24px' }}>
          <label style={{
            display: 'block',
            marginBottom: '10px',
            fontWeight: 600,
            fontSize: '15px',
            color: '#495057'
          }}>
            <span style={{ marginRight: '8px' }}>🏢</span>
            Company Name <span style={{ color: '#6c757d', fontWeight: 400 }}>(Optional)</span>
          </label>
          <input
            type="text"
            value={companyName}
            onChange={(e) => setCompanyName(e.target.value)}
            placeholder="e.g., Google, Microsoft, Amazon..."
            style={{
              width: '100%',
              padding: '12px 14px',
              fontSize: '15px',
              border: '2px solid #e9ecef',
              borderRadius: '10px',
              outline: 'none',
              transition: 'all 0.2s'
            }}
            onFocus={(e) => e.target.style.borderColor = '#667eea'}
            onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
          />
          <div style={{ 
            fontSize: '13px', 
            color: '#6c757d', 
            marginTop: '8px',
            display: 'flex',
            alignItems: 'center',
            gap: '6px'
          }}>
            <span>💡</span>
            <span>Questions will be tailored to the company's culture and interview style</span>
          </div>
        </div>

        {/* Resume Upload - Only show for Resume Digging */}
        {interviewType === 'Resume Digging' && (
          <div style={{ marginBottom: '24px' }}>
            <label style={{
              display: 'block',
              marginBottom: '10px',
              fontWeight: 600,
              fontSize: '15px',
              color: '#495057'
            }}>
              <span style={{ marginRight: '8px' }}>📎</span>
              Upload Resume <span style={{ color: '#e84a5f', fontWeight: 600 }}>(Required)</span>
            </label>
            <div style={{
              border: '2px dashed #667eea',
              borderRadius: '10px',
              padding: '20px',
              textAlign: 'center',
              backgroundColor: resumeText ? '#f0f7ff' : '#fafbfc',
              transition: 'all 0.2s'
            }}>
              {!resumeText ? (
                <>
                  <input
                    type="file"
                    accept=".pdf,.doc,.docx,application/pdf,application/msword,application/vnd.openxmlformats-officedocument.wordprocessingml.document"
                    onChange={handleResumeUpload}
                    disabled={uploadingResume}
                    style={{ display: 'none' }}
                    id="resume-upload"
                  />
                  <label
                    htmlFor="resume-upload"
                    style={{
                      display: 'inline-block',
                      padding: '12px 24px',
                      background: uploadingResume ? '#6c757d' : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                      color: 'white',
                      borderRadius: '8px',
                      cursor: uploadingResume ? 'not-allowed' : 'pointer',
                      fontSize: '15px',
                      fontWeight: 600,
                      transition: 'transform 0.2s'
                    }}
                    onMouseEnter={(e) => {
                      if (!uploadingResume) e.target.style.transform = 'scale(1.05)';
                    }}
                    onMouseLeave={(e) => {
                      if (!uploadingResume) e.target.style.transform = 'scale(1)';
                    }}
                  >
                    {uploadingResume ? '⏳ Processing...' : '📤 Choose Resume File'}
                  </label>
                  <div style={{ marginTop: '12px', fontSize: '13px', color: '#6c757d' }}>
                    Supports PDF, DOC, DOCX (max 10MB)
                  </div>
                </>
              ) : (
                <div>
                  <div style={{ fontSize: '32px', marginBottom: '8px' }}>✅</div>
                  <div style={{ fontSize: '15px', color: '#212529', fontWeight: 600, marginBottom: '4px' }}>
                    {resumeFileName || 'Resume uploaded'}
                  </div>
                  <div style={{ fontSize: '13px', color: '#6c757d', marginBottom: '12px' }}>
                    {resumeText.length} characters extracted
                  </div>
                  <button
                    onClick={() => {
                      setResumeText('');
                      setResumeFileName('');
                    }}
                    style={{
                      padding: '8px 16px',
                      backgroundColor: '#dc3545',
                      color: 'white',
                      border: 'none',
                      borderRadius: '6px',
                      cursor: 'pointer',
                      fontSize: '13px',
                      fontWeight: 500
                    }}
                  >
                    Remove Resume
                  </button>
                </div>
              )}
            </div>
            <div style={{ 
              fontSize: '13px', 
              color: '#6c757d', 
              marginTop: '8px',
              display: 'flex',
              alignItems: 'center',
              gap: '6px'
            }}>
              <span>💡</span>
              <span>AI will analyze your resume and ask questions about your experience</span>
            </div>
          </div>
        )}

        {/* Job Description */}
        {interviewType !== 'Resume Digging' && (
          <div style={{ marginBottom: '32px' }}>
            <label style={{
              display: 'block',
              marginBottom: '10px',
              fontWeight: 600,
              fontSize: '15px',
              color: '#495057'
            }}>
              <span style={{ marginRight: '8px' }}>📄</span>
              Job Description <span style={{ color: '#6c757d', fontWeight: 400 }}>(Optional)</span>
            </label>
            <textarea
              value={jobDescription}
              onChange={(e) => setJobDescription(e.target.value)}
              placeholder="Paste job description or role details here to get more tailored questions..."
              rows={6}
              style={{
                width: '100%',
                padding: '12px 14px',
                fontSize: '14px',
                border: '2px solid #e9ecef',
                borderRadius: '10px',
                fontFamily: 'inherit',
                resize: 'vertical',
                lineHeight: '1.6',
                transition: 'all 0.2s',
                outline: 'none'
              }}
              onFocus={(e) => e.target.style.borderColor = '#667eea'}
              onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
            />
            <div style={{ 
              fontSize: '13px', 
              color: '#6c757d', 
              marginTop: '8px',
              display: 'flex',
              alignItems: 'center',
              gap: '6px'
            }}>
              <span>💡</span>
              <span>Adding a job description improves question quality and relevance</span>
            </div>
          </div>
        )}

        {/* Start Button */}
        <button
          onClick={onStartSession}
          disabled={isLoading || (interviewType === 'Resume Digging' && !resumeText)}
          style={{
            width: '100%',
            padding: '16px',
            background: (isLoading || (interviewType === 'Resume Digging' && !resumeText))
              ? '#6c757d' 
              : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            color: 'white',
            border: 'none',
            borderRadius: '12px',
            fontSize: '18px',
            fontWeight: 700,
            cursor: (isLoading || (interviewType === 'Resume Digging' && !resumeText)) ? 'not-allowed' : 'pointer',
            transition: 'all 0.3s',
            boxShadow: (isLoading || (interviewType === 'Resume Digging' && !resumeText))
              ? 'none' 
              : '0 4px 15px rgba(102, 126, 234, 0.4)',
            transform: (isLoading || (interviewType === 'Resume Digging' && !resumeText)) ? 'none' : 'translateY(0)'
          }}
          onMouseEnter={(e) => {
            if (!isLoading && !(interviewType === 'Resume Digging' && !resumeText)) {
              e.target.style.transform = 'translateY(-2px)';
              e.target.style.boxShadow = '0 6px 20px rgba(102, 126, 234, 0.5)';
            }
          }}
          onMouseLeave={(e) => {
            if (!isLoading && !(interviewType === 'Resume Digging' && !resumeText)) {
              e.target.style.transform = 'translateY(0)';
              e.target.style.boxShadow = '0 4px 15px rgba(102, 126, 234, 0.4)';
            }
          }}
        >
          {isLoading ? (
            <span>⏳ Generating Question...</span>
          ) : (interviewType === 'Resume Digging' && !resumeText) ? (
            <span>📎 Please Upload Resume First</span>
          ) : (
            <span>🚀 Start Interview Session</span>
          )}
        </button>
      </div>
    </div>
  );
}

export default InterviewControls;

sources.components/InterviewSession.jsx:
import React, { useState } from 'react';
import VoiceRecorder from './VoiceRecorder.jsx';

function InterviewSession({
  currentQuestion,
  userAnswer,
  setUserAnswer,
  onSubmitAnswer,
  onGenerateAnother,
  onShowHint,
  onSaveAnswer,
  isLoading,
  hasAnswer,
  hint,
  onClearHint
}) {
  const [inputMode, setInputMode] = useState('text'); // 'text' or 'voice'

  // Handle transcription from voice recorder
  const handleTranscription = (transcribedText) => {
    // Append or replace the answer with transcribed text
    if (userAnswer.trim()) {
      // If there's existing text, append with a space
      setUserAnswer(userAnswer + ' ' + transcribedText);
    } else {
      // Otherwise, just set the transcribed text
      setUserAnswer(transcribedText);
    }
    // Switch back to text mode so user can see/edit the transcription
    setInputMode('text');
  };
  return (
    <div style={{ maxWidth: '900px', margin: '0 auto' }}>
      {/* Question Box */}
      <div style={{
        backgroundColor: 'white',
        padding: '24px',
        borderRadius: '12px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
        marginBottom: '20px',
        border: '2px solid #007bff'
      }}>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          marginBottom: '12px'
        }}>
          <span style={{
            fontSize: '24px',
            marginRight: '12px'
          }}>
            💬
          </span>
          <h3 style={{ margin: 0, color: '#007bff', fontSize: '16px', fontWeight: 600 }}>
            Interview Question
          </h3>
        </div>
        <div style={{
          fontSize: '16px',
          lineHeight: '1.6',
          color: '#212529',
          fontWeight: 500
        }}>
          {currentQuestion || 'Loading question...'}
        </div>
      </div>

      {/* Hint Box - Shows when hint is available */}
      {hint && (
        <div style={{
          backgroundColor: '#fff3cd',
          padding: '20px',
          borderRadius: '12px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          marginBottom: '20px',
          border: '2px solid #ffc107',
          position: 'relative'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: '12px'
          }}>
            <div style={{ display: 'flex', alignItems: 'center' }}>
              <span style={{
                fontSize: '24px',
                marginRight: '12px'
              }}>
                💡
              </span>
              <h3 style={{ margin: 0, color: '#856404', fontSize: '16px', fontWeight: 600 }}>
                STAR Framework Hint
              </h3>
            </div>
            <button
              onClick={onClearHint}
              style={{
                padding: '4px 12px',
                backgroundColor: '#856404',
                color: 'white',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                fontSize: '12px',
                fontWeight: 500
              }}
            >
              ✕ Close
            </button>
          </div>
          <div style={{
            fontSize: '14px',
            lineHeight: '1.6',
            color: '#212529',
            whiteSpace: 'pre-wrap'
          }}>
            {hint}
          </div>
        </div>
      )}

      {/* Answer Input Area */}
      <div style={{
        backgroundColor: 'white',
        padding: '24px',
        borderRadius: '12px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
        marginBottom: '20px'
      }}>
        {/* Input Mode Toggle */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '16px'
        }}>
          <label style={{
            fontWeight: 600,
            fontSize: '14px',
            color: '#495057'
          }}>
            Your Answer
          </label>
          <div style={{
            display: 'flex',
            gap: '8px',
            backgroundColor: '#f8f9fa',
            padding: '4px',
            borderRadius: '8px',
            border: '1px solid #e9ecef'
          }}>
            <button
              onClick={() => setInputMode('text')}
              style={{
                padding: '6px 16px',
                backgroundColor: inputMode === 'text' ? '#667eea' : 'transparent',
                color: inputMode === 'text' ? 'white' : '#6c757d',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                fontSize: '13px',
                fontWeight: 600,
                transition: 'all 0.2s',
                display: 'flex',
                alignItems: 'center',
                gap: '6px'
              }}
            >
              <span>⌨️</span>
              <span>Type</span>
            </button>
            <button
              onClick={() => setInputMode('voice')}
              style={{
                padding: '6px 16px',
                backgroundColor: inputMode === 'voice' ? '#667eea' : 'transparent',
                color: inputMode === 'voice' ? 'white' : '#6c757d',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                fontSize: '13px',
                fontWeight: 600,
                transition: 'all 0.2s',
                display: 'flex',
                alignItems: 'center',
                gap: '6px'
              }}
            >
              <span>🎤</span>
              <span>Speak</span>
            </button>
          </div>
        </div>

        {/* Voice Recorder (shown in voice mode) */}
        {inputMode === 'voice' && (
          <VoiceRecorder 
            onTranscriptionComplete={handleTranscription}
            isLoading={isLoading}
          />
        )}

        {/* Text Input (shown in text mode) */}
        {inputMode === 'text' && (
          <>
            <textarea
              value={userAnswer}
              onChange={(e) => setUserAnswer(e.target.value)}
              placeholder="Type your answer here... Try to use the STAR format: Situation, Task, Action, Result"
              rows={10}
              style={{
                width: '100%',
                padding: '12px',
                fontSize: '14px',
                border: '1px solid #ced4da',
                borderRadius: '8px',
                fontFamily: 'inherit',
                resize: 'vertical',
                lineHeight: '1.6'
              }}
            />
            <div style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginTop: '8px'
            }}>
              <div style={{ fontSize: '12px', color: '#6c757d' }}>
                {userAnswer.length} characters
              </div>
              <div style={{ fontSize: '12px', color: userAnswer.length < 100 ? '#dc3545' : '#28a745' }}>
                {userAnswer.length < 100 ? '⚠️ Try to provide more detail' : '✓ Good length'}
              </div>
            </div>
          </>
        )}

        {/* Action Buttons */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
          gap: '12px',
          marginTop: '20px'
        }}>
          <button
            onClick={onSubmitAnswer}
            disabled={!hasAnswer || isLoading}
            style={{
              padding: '12px 16px',
              backgroundColor: !hasAnswer || isLoading ? '#6c757d' : '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: !hasAnswer || isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
          >
            <span>✅</span>
            <span>{isLoading ? 'Analyzing...' : 'Submit Answer'}</span>
          </button>

          <button
            onClick={onGenerateAnother}
            disabled={isLoading}
            style={{
              padding: '12px 16px',
              backgroundColor: isLoading ? '#6c757d' : '#007bff',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
          >
            <span>🔄</span>
            <span>New Question</span>
          </button>

          <button
            onClick={onShowHint}
            disabled={isLoading}
            style={{
              padding: '12px 16px',
              backgroundColor: isLoading ? '#6c757d' : '#ffc107',
              color: '#212529',
              border: 'none',
              borderRadius: '8px',
              cursor: isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
          >
            <span>💡</span>
            <span>Show Hint</span>
          </button>

          <button
            onClick={onSaveAnswer}
            disabled={!hasAnswer || isLoading}
            style={{
              padding: '12px 16px',
              backgroundColor: !hasAnswer || isLoading ? '#6c757d' : '#17a2b8',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: !hasAnswer || isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px'
            }}
          >
            <span>💾</span>
            <span>Save Answer</span>
          </button>
        </div>
      </div>
    </div>
  );
}

export default InterviewSession;

