import React, { useState, useRef, useEffect } from 'react';

function VoiceRecorder({ onTranscriptionComplete, isLoading }) {
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState('');

  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const timerIntervalRef = useRef(null);

  // Format time as MM:SS
  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  // Start recording
  const startRecording = async () => {
    try {
      setError('');
      setRecordingTime(0); // Reset timer before starting

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      // Create MediaRecorder with appropriate MIME type
      const mimeType = MediaRecorder.isTypeSupported('audio/webm') 
        ? 'audio/webm' 
        : 'audio/mp4';

      const mediaRecorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        // Stop all tracks
        stream.getTracks().forEach(track => track.stop());

        // Process the recording
        await processRecording();
      };

      // Start recording first
      mediaRecorder.start();
      setIsRecording(true);

      // Start timer AFTER setting recording state
      timerIntervalRef.current = setInterval(() => {
        setRecordingTime(prev => {
          const newTime = prev + 1;
          return newTime;
        });
      }, 1000);

    } catch (err) {
      console.error('Error starting recording:', err);
      setError('Could not access microphone. Please check permissions.');
    }
  };

  // Stop recording
  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);

      // Clear timer
      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }
    }
  };

  // Process the recorded audio
  const processRecording = async () => {
    if (audioChunksRef.current.length === 0) {
      setError('No audio data recorded');
      return;
    }

    setIsProcessing(true);
    setError('');

    try {
      // Create blob from audio chunks
      const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });

      // Convert to base64
      const reader = new FileReader();
      reader.onloadend = async () => {
        try {
          const base64Audio = reader.result.split(',')[1]; // Remove data:audio/webm;base64, prefix

          // Call speech-to-text API
          const transcription = await miyagiAPI('speech-to-text', {
            audio: base64Audio,
            model: 'whisper-1',
            language: 'en',
            response_format: 'text'
          });

          // Pass transcription back to parent
          if (transcription && typeof transcription === 'string') {
            onTranscriptionComplete(transcription);
          } else {
            throw new Error('Invalid transcription response');
          }

        } catch (err) {
          console.error('Error transcribing audio:', err);
          setError('Failed to transcribe audio. Please try again.');
        } finally {
          setIsProcessing(false);
        }
      };

      reader.onerror = () => {
        setError('Failed to process audio file');
        setIsProcessing(false);
      };

      reader.readAsDataURL(audioBlob);

    } catch (err) {
      console.error('Error processing recording:', err);
      setError('Failed to process recording. Please try again.');
      setIsProcessing(false);
    }
  };

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (timerIntervalRef.current) {
        clearInterval(timerIntervalRef.current);
        timerIntervalRef.current = null;
      }
      if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
      }
    };
  }, []);

  return (
    <div style={{
      backgroundColor: '#f8f9fa',
      padding: '20px',
      borderRadius: '12px',
      border: '2px solid #e9ecef',
      marginBottom: '16px'
    }}>
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        marginBottom: '16px'
      }}>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '12px'
        }}>
          <span style={{ fontSize: '24px' }}>🎤</span>
          <div>
            <h4 style={{ margin: 0, fontSize: '16px', fontWeight: 600, color: '#212529' }}>
              Voice Answer
            </h4>
            <p style={{ margin: '4px 0 0 0', fontSize: '13px', color: '#6c757d' }}>
              {isRecording ? 'Recording...' : isProcessing ? 'Transcribing...' : 'Click to record your answer'}
            </p>
          </div>
        </div>

        {/* Timer Display */}
        <div style={{
          fontSize: '20px',
          fontWeight: 700,
          color: isRecording ? '#dc3545' : '#6c757d',
          fontFamily: 'monospace',
          display: 'flex',
          alignItems: 'center',
          gap: '8px',
          minWidth: '80px',
          justifyContent: 'flex-end'
        }}>
          {isRecording && (
            <span style={{
              width: '12px',
              height: '12px',
              backgroundColor: '#dc3545',
              borderRadius: '50%',
              animation: 'pulse 1.5s infinite'
            }} />
          )}
          {formatTime(recordingTime)}
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div style={{
          padding: '12px',
          backgroundColor: '#f8d7da',
          color: '#721c24',
          borderRadius: '8px',
          marginBottom: '12px',
          fontSize: '14px',
          border: '1px solid #f5c6cb'
        }}>
          ⚠️ {error}
        </div>
      )}

      {/* Recording Controls */}
      <div style={{
        display: 'flex',
        gap: '12px'
      }}>
        {!isRecording ? (
          <button
            onClick={startRecording}
            disabled={isProcessing || isLoading}
            style={{
              flex: 1,
              padding: '14px 20px',
              backgroundColor: isProcessing || isLoading ? '#6c757d' : '#dc3545',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: isProcessing || isLoading ? 'not-allowed' : 'pointer',
              fontSize: '15px',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px',
              transition: 'all 0.2s'
            }}
            onMouseEnter={(e) => {
              if (!isProcessing && !isLoading) {
                e.target.style.backgroundColor = '#c82333';
              }
            }}
            onMouseLeave={(e) => {
              if (!isProcessing && !isLoading) {
                e.target.style.backgroundColor = '#dc3545';
              }
            }}
          >
            <span style={{ fontSize: '20px' }}>🎙️</span>
            <span>{isProcessing ? 'Transcribing...' : 'Start Recording'}</span>
          </button>
        ) : (
          <button
            onClick={stopRecording}
            style={{
              flex: 1,
              padding: '14px 20px',
              backgroundColor: '#28a745',
              color: 'white',
              border: 'none',
              borderRadius: '8px',
              cursor: 'pointer',
              fontSize: '15px',
              fontWeight: 600,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '8px',
              transition: 'all 0.2s'
            }}
            onMouseEnter={(e) => {
              e.target.style.backgroundColor = '#218838';
            }}
            onMouseLeave={(e) => {
              e.target.style.backgroundColor = '#28a745';
            }}
          >
            <span style={{ fontSize: '20px' }}>⏹️</span>
            <span>Stop & Transcribe</span>
          </button>
        )}
      </div>

      {/* Recording Tips */}
      {!isRecording && !isProcessing && (
        <div style={{
          marginTop: '12px',
          padding: '12px',
          backgroundColor: '#d1ecf1',
          borderRadius: '8px',
          fontSize: '13px',
          color: '#0c5460',
          border: '1px solid #bee5eb'
        }}>
          <strong>💡 Tips:</strong> Speak clearly, pause between thoughts, and use the STAR format (Situation, Task, Action, Result)
        </div>
      )}

      {/* Add CSS animation for pulse effect */}
      <style>{`
        @keyframes pulse {
          0%, 100% {
            opacity: 1;
          }
          50% {
            opacity: 0.3;
          }
        }
      `}</style>
    </div>
  );
}

export default VoiceRecorder;

