import React, { useState, useCallback, useEffect } from 'react';
import WarmUpSelector from './components/WarmUpSelector.jsx';
import TrainingZone from './components/TrainingZone.jsx';

// Drill configurations
const DRILL_CONFIGS = {
  'elevator-pitch': {
    count: 1,
    prompts: [
      'Give me your 30-second elevator pitch. Who are you, what do you do, and what makes you unique?'
    ]
  },
  'rapid-behavioral': {
    count: 5,
    prompts: [
      'Tell me about a time you faced a significant challenge at work.',
      'Describe a situation where you had to work with a difficult team member.',
      'Share an example of when you took initiative on a project.',
      'Tell me about a time you failed and what you learned.',
      'Describe a situation where you had to meet a tight deadline.'
    ]
  },
  'company-fit': {
    count: 3,
    prompts: [
      'Why are you interested in this company?',
      'Why do you want this specific role?',
      'What do you know about our company culture and how do you fit in?'
    ]
  },
  'explain-technical': {
    count: 3,
    prompts: [
      'Explain machine learning to a non-technical person.',
      'How would you describe an API to someone without a technical background?',
      'Explain what a database is to a 10-year-old.'
    ]
  },
  'metrics-impact': {
    count: 3,
    prompts: [
      'Describe a project where you had measurable impact. What were the numbers?',
      'Tell me about a time you improved efficiency. How did you quantify the improvement?',
      'Share an achievement where you can demonstrate ROI or business value.'
    ]
  },
  'tell-me-about': {
    count: 1,
    prompts: [
      'Tell me about yourself. Walk me through your background and what brings you here today.'
    ]
  },
  'tricky-pressure': {
    count: 3,
    prompts: [
      'What is your biggest weakness?',
      'Why should we hire you over other candidates?',
      'Where do you see yourself in 5 years?'
    ]
  }
};

function MicroDrills() {
  // Widget storage
  const [jobDescription, setJobDescription] = useStorage('job-description', '');
  const [drillHistory, setDrillHistory] = useStorage('drill-history', []);

  // Session state
  const [selectedDrill, setSelectedDrill] = useState(null);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [currentQuestion, setCurrentQuestion] = useState('');
  const [userAnswer, setUserAnswer] = useState('');
  const [feedback, setFeedback] = useState(null);
  const [isLoading, setIsLoading] = useState(false);
  const [timerDuration, setTimerDuration] = useState(60); // Default 1 minute
  const [sessionActive, setSessionActive] = useState(false);

  // Generate question based on drill type
  const generateQuestion = useCallback(async (drillType, questionIndex) => {
    setIsLoading(true);
    setFeedback(null);
    setUserAnswer('');

    try {
      const config = DRILL_CONFIGS[drillType];

      // Use predefined prompt or generate custom one
      if (config.prompts[questionIndex]) {
        let question = config.prompts[questionIndex];

        // If job description is provided, customize the question
        if (jobDescription.trim()) {
          const customPrompt = `Based on this job description: "${jobDescription.substring(0, 200)}...", 
          customize this interview question to be more relevant: "${question}". 
          Return only the customized question, no additional text.`;

          try {
            const customQuestion = await miyagiAPI('generate-text', {
              prompt: customPrompt,
              provider: 'openai',
              model: 'gpt-4o-mini',
              max_tokens: 150,
              temperature: 0.7
            });
            question = customQuestion;
          } catch (error) {
            console.error('Error customizing question:', error);
            // Fall back to original question
          }
        }

        setCurrentQuestion(question);
      }
    } catch (error) {
      console.error('Error generating question:', error);
      setCurrentQuestion('Error generating question. Please try again.');
    } finally {
      setIsLoading(false);
    }
  }, [jobDescription]);

  // Handle drill selection
  const handleSelectDrill = useCallback(async (drillType) => {
    setSelectedDrill(drillType);
    setCurrentQuestionIndex(0);
    setSessionActive(true);
    await generateQuestion(drillType, 0);
  }, [generateQuestion]);

  // Submit answer for micro feedback
  const handleSubmitAnswer = useCallback(async () => {
    if (!userAnswer.trim()) return;

    setIsLoading(true);

    try {
      const systemPrompt = `You are a concise interview coach. Provide ultra-brief feedback in this EXACT JSON format:
{"good": "one positive thing (max 15 words)", "try": "one improvement suggestion with example (max 20 words)", "sharper": "improved 1-2 sentence version"}

Be specific, actionable, and concise. Focus on structure, clarity, and impact.`;

      const prompt = `Question: ${currentQuestion}
Answer: ${userAnswer}

Provide micro-feedback.`;

      const feedbackText = await miyagiAPI('generate-text', {
        prompt,
        system_prompt: systemPrompt,
        provider: 'openai',
        model: 'gpt-4o',
        max_tokens: 400,
        temperature: 0.7
      });

      // Parse JSON response
      let parsedFeedback;
      try {
        let cleanedText = feedbackText.trim();
        if (cleanedText.startsWith('```json')) {
          cleanedText = cleanedText.replace(/^```json\s*/, '').replace(/\s*```$/, '');
        } else if (cleanedText.startsWith('```')) {
          cleanedText = cleanedText.replace(/^```\s*/, '').replace(/\s*```$/, '');
        }
        parsedFeedback = JSON.parse(cleanedText);
      } catch (e) {
        console.error('JSON parse error:', e);
        parsedFeedback = {
          good: 'Good attempt',
          try: 'Add more specific details',
          sharper: feedbackText
        };
      }

      setFeedback(parsedFeedback);

      // Save to history
      setDrillHistory(prev => [{
        drillType: selectedDrill,
        question: currentQuestion,
        answer: userAnswer,
        feedback: parsedFeedback,
        timestamp: new Date().toISOString()
      }, ...prev.slice(0, 49)]); // Keep last 50

    } catch (error) {
      console.error('Error getting feedback:', error);
      setFeedback({
        good: 'Answer recorded',
        try: 'Error generating feedback',
        sharper: ''
      });
    } finally {
      setIsLoading(false);
    }
  }, [userAnswer, currentQuestion, selectedDrill]);

  // Move to next question
  const handleNext = useCallback(async () => {
    const config = DRILL_CONFIGS[selectedDrill];
    const nextIndex = currentQuestionIndex + 1;

    if (nextIndex < config.count) {
      setCurrentQuestionIndex(nextIndex);
      await generateQuestion(selectedDrill, nextIndex);
    } else {
      // Drill complete
      setSessionActive(false);
      setSelectedDrill(null);
      setCurrentQuestionIndex(0);
      setCurrentQuestion('');
      setUserAnswer('');
      setFeedback(null);
    }
  }, [selectedDrill, currentQuestionIndex, generateQuestion]);

  // End session
  const handleEndSession = useCallback(() => {
    setSessionActive(false);
    setSelectedDrill(null);
    setCurrentQuestionIndex(0);
    setCurrentQuestion('');
    setUserAnswer('');
    setFeedback(null);
  }, []);

  return (
    <div style={{
      width: '100%',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      backgroundColor: '#f8f9fa',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
      overflow: 'hidden'
    }}>
      {/* Header */}
      <div style={{
        padding: '20px 24px',
        background: 'linear-gradient(135deg, #ff6b6b 0%, #ee5a6f 100%)',
        borderBottom: '3px solid #e84a5f',
        boxShadow: '0 4px 12px rgba(255, 107, 107, 0.3)'
      }}>
        <h2 style={{ 
          margin: 0, 
          fontSize: '24px', 
          color: '#fff', 
          fontWeight: 700,
          display: 'flex',
          alignItems: 'center',
          gap: '12px'
        }}>
          <span style={{ fontSize: '28px' }}>{'\u{1F525}'}</span>
          <span>Micro-Drills & Warm-Up</span>
        </h2>
        <p style={{ 
          margin: '8px 0 0 40px', 
          fontSize: '13px', 
          color: 'rgba(255,255,255,0.9)',
          fontWeight: 400
        }}>
          Quick practice sessions to sharpen your interview reflexes
        </p>
      </div>

      {/* Content Area */}
      <div style={{
        flex: 1,
        overflow: 'auto',
        padding: '20px'
      }}>
        {!sessionActive ? (
          <WarmUpSelector
            onSelectDrill={handleSelectDrill}
            jobDescription={jobDescription}
            setJobDescription={setJobDescription}
          />
        ) : (
          <TrainingZone
            currentQuestion={currentQuestion}
            userAnswer={userAnswer}
            setUserAnswer={setUserAnswer}
            onSubmit={handleSubmitAnswer}
            onNext={handleNext}
            feedback={feedback}
            isLoading={isLoading}
            timerDuration={timerDuration}
            setTimerDuration={setTimerDuration}
            drillType={selectedDrill}
            questionNumber={currentQuestionIndex + 1}
            totalQuestions={DRILL_CONFIGS[selectedDrill]?.count || 1}
          />
        )}
      </div>

      {/* Footer - Session Controls */}
      {sessionActive && (
        <div style={{
          padding: '12px 20px',
          backgroundColor: '#fff',
          borderTop: '1px solid #e9ecef',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}>
          <button
            onClick={handleEndSession}
            style={{
              padding: '8px 16px',
              backgroundColor: '#6c757d',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              cursor: 'pointer',
              fontSize: '14px',
              fontWeight: 500
            }}
          >
            End Drill
          </button>
          <div style={{ fontSize: '12px', color: '#6c757d' }}>
            Total drills completed: {drillHistory.length}
          </div>
        </div>
      )}
    </div>
  );
}

export default MicroDrills;

