import React, { useState, useEffect, useRef } from 'react';
import VoiceRecorder from './VoiceRecorder.jsx';

function TrainingZone({
  currentQuestion,
  userAnswer,
  setUserAnswer,
  onSubmit,
  onNext,
  feedback,
  isLoading,
  timerDuration,
  setTimerDuration,
  drillType,
  questionNumber,
  totalQuestions
}) {
  const [timeLeft, setTimeLeft] = useState(null);
  const [timerActive, setTimerActive] = useState(false);
  const [inputMode, setInputMode] = useState('text'); // 'text' or 'voice'
  const timerRef = useRef(null);

  // Handle transcription from voice recorder
  const handleTranscription = (transcribedText) => {
    // Append or replace the answer with transcribed text
    if (userAnswer.trim()) {
      // If there's existing text, append with a space
      setUserAnswer(userAnswer + ' ' + transcribedText);
    } else {
      // Otherwise, just set the transcribed text
      setUserAnswer(transcribedText);
    }
    // Switch back to text mode so user can see/edit the transcription
    setInputMode('text');
  };

  const TIMER_OPTIONS = [
    { value: 30, label: '30s' },
    { value: 60, label: '1min' },
    { value: 120, label: '2min' },
    { value: null, label: 'No timer' }
  ];

  // Timer logic
  useEffect(() => {
    if (timerActive && timeLeft !== null && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            setTimerActive(false);
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }

    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [timerActive, timeLeft]);

  const handleStartTimer = () => {
    if (timerDuration) {
      setTimeLeft(timerDuration);
      setTimerActive(true);
    }
  };

  const handleStopTimer = () => {
    setTimerActive(false);
    setTimeLeft(null);
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getTimerColor = () => {
    if (!timeLeft || !timerDuration) return '#6c757d';
    const percentage = (timeLeft / timerDuration) * 100;
    if (percentage > 50) return '#28a745';
    if (percentage > 20) return '#ffc107';
    return '#dc3545';
  };

  return (
    <div style={{ maxWidth: '900px', margin: '0 auto' }}>
      {/* Progress Indicator */}
      {totalQuestions > 1 && (
        <div style={{
          backgroundColor: 'white',
          padding: '12px 20px',
          borderRadius: '10px',
          marginBottom: '16px',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          boxShadow: '0 2px 8px rgba(0,0,0,0.08)'
        }}>
          <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: 500 }}>
            Question {questionNumber} of {totalQuestions}
          </div>
          <div style={{
            display: 'flex',
            gap: '6px'
          }}>
            {Array.from({ length: totalQuestions }).map((_, idx) => (
              <div
                key={idx}
                style={{
                  width: '8px',
                  height: '8px',
                  borderRadius: '50%',
                  backgroundColor: idx < questionNumber ? '#ff6b6b' : '#e9ecef'
                }}
              />
            ))}
          </div>
        </div>
      )}

      {/* Question Box */}
      <div style={{
        backgroundColor: 'white',
        padding: '24px',
        borderRadius: '12px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
        marginBottom: '20px',
        border: '2px solid #ff6b6b'
      }}>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: '12px'
        }}>
          <div style={{ display: 'flex', alignItems: 'center' }}>
            <span style={{ fontSize: '24px', marginRight: '12px' }}>💬</span>
            <h3 style={{ margin: 0, color: '#ff6b6b', fontSize: '16px', fontWeight: 600 }}>
              Warm-Up Question
            </h3>
          </div>

          {/* Timer Display */}
          {timeLeft !== null && (
            <div style={{
              fontSize: '20px',
              fontWeight: 700,
              color: getTimerColor(),
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>⏱️</span>
              <span>{formatTime(timeLeft)}</span>
            </div>
          )}
        </div>
        <div style={{
          fontSize: '16px',
          lineHeight: '1.6',
          color: '#212529',
          fontWeight: 500
        }}>
          {currentQuestion || 'Loading question...'}
        </div>
      </div>

      {/* Timer Controls */}
      <div style={{
        backgroundColor: 'white',
        padding: '16px 20px',
        borderRadius: '10px',
        marginBottom: '20px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.08)'
      }}>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '12px',
          flexWrap: 'wrap'
        }}>
          <span style={{ fontSize: '13px', fontWeight: 600, color: '#495057' }}>
            Timer:
          </span>
          {TIMER_OPTIONS.map(option => (
            <button
              key={option.value || 'none'}
              onClick={() => {
                setTimerDuration(option.value);
                handleStopTimer();
              }}
              style={{
                padding: '6px 14px',
                fontSize: '13px',
                fontWeight: 500,
                border: timerDuration === option.value ? '2px solid #ff6b6b' : '2px solid #e9ecef',
                backgroundColor: timerDuration === option.value ? '#fff5f5' : 'white',
                color: timerDuration === option.value ? '#ff6b6b' : '#6c757d',
                borderRadius: '16px',
                cursor: 'pointer',
                transition: 'all 0.2s'
              }}
            >
              {option.label}
            </button>
          ))}
          {timerDuration && !timerActive && timeLeft === null && (
            <button
              onClick={handleStartTimer}
              style={{
                padding: '6px 14px',
                fontSize: '13px',
                fontWeight: 600,
                backgroundColor: '#28a745',
                color: 'white',
                border: 'none',
                borderRadius: '16px',
                cursor: 'pointer'
              }}
            >
              ▶️ Start Timer
            </button>
          )}
          {timerActive && (
            <button
              onClick={handleStopTimer}
              style={{
                padding: '6px 14px',
                fontSize: '13px',
                fontWeight: 600,
                backgroundColor: '#dc3545',
                color: 'white',
                border: 'none',
                borderRadius: '16px',
                cursor: 'pointer'
              }}
            >
              ⏸️ Stop
            </button>
          )}
        </div>
      </div>

      {/* Answer Input */}
      {!feedback && (
        <div style={{
          backgroundColor: 'white',
          padding: '24px',
          borderRadius: '12px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          marginBottom: '20px'
        }}>
          {/* Input Mode Toggle */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: '16px'
          }}>
            <label style={{
              fontWeight: 600,
              fontSize: '14px',
              color: '#495057'
            }}>
              Your Answer
            </label>
            <div style={{
              display: 'flex',
              gap: '8px',
              backgroundColor: '#f8f9fa',
              padding: '4px',
              borderRadius: '8px',
              border: '1px solid #e9ecef'
            }}>
              <button
                onClick={() => setInputMode('text')}
                style={{
                  padding: '6px 16px',
                  backgroundColor: inputMode === 'text' ? '#ff6b6b' : 'transparent',
                  color: inputMode === 'text' ? 'white' : '#6c757d',
                  border: 'none',
                  borderRadius: '6px',
                  cursor: 'pointer',
                  fontSize: '13px',
                  fontWeight: 600,
                  transition: 'all 0.2s',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px'
                }}
              >
                <span>⌨️</span>
                <span>Type</span>
              </button>
              <button
                onClick={() => setInputMode('voice')}
                style={{
                  padding: '6px 16px',
                  backgroundColor: inputMode === 'voice' ? '#ff6b6b' : 'transparent',
                  color: inputMode === 'voice' ? 'white' : '#6c757d',
                  border: 'none',
                  borderRadius: '6px',
                  cursor: 'pointer',
                  fontSize: '13px',
                  fontWeight: 600,
                  transition: 'all 0.2s',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px'
                }}
              >
                <span>🎤</span>
                <span>Speak</span>
              </button>
            </div>
          </div>

          {/* Voice Recorder (shown in voice mode) */}
          {inputMode === 'voice' && (
            <VoiceRecorder 
              onTranscriptionComplete={handleTranscription}
              isLoading={isLoading}
            />
          )}

          {/* Text Input (shown in text mode) */}
          {inputMode === 'text' && (
            <>
              <textarea
                value={userAnswer}
                onChange={(e) => setUserAnswer(e.target.value)}
                placeholder="Type your answer here..."
                rows={8}
                style={{
                  width: '100%',
                  padding: '12px',
                  fontSize: '14px',
                  border: '1px solid #ced4da',
                  borderRadius: '8px',
                  fontFamily: 'inherit',
                  resize: 'vertical',
                  lineHeight: '1.6',
                  outline: 'none'
                }}
                onFocus={(e) => e.target.style.borderColor = '#ff6b6b'}
                onBlur={(e) => e.target.style.borderColor = '#ced4da'}
              />
              <div style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                marginTop: '8px'
              }}>
                <div style={{ fontSize: '12px', color: '#6c757d' }}>
                  {userAnswer.length} characters
                </div>
              </div>
            </>
          )}

          <button
            onClick={onSubmit}
            disabled={!userAnswer.trim() || isLoading}
            style={{
              width: '100%',
              marginTop: '16px',
              padding: '12px 16px',
              backgroundColor: !userAnswer.trim() || isLoading ? '#6c757d' : '#ff6b6b',
              color: 'white',
              border: 'none',
              borderRadius: '10px',
              cursor: !userAnswer.trim() || isLoading ? 'not-allowed' : 'pointer',
              fontSize: '15px',
              fontWeight: 600,
              transition: 'all 0.2s',
              boxShadow: !userAnswer.trim() || isLoading ? 'none' : '0 4px 12px rgba(255, 107, 107, 0.3)'
            }}
            onMouseEnter={(e) => {
              if (userAnswer.trim() && !isLoading) {
                e.target.style.transform = 'translateY(-2px)';
                e.target.style.boxShadow = '0 6px 16px rgba(255, 107, 107, 0.4)';
              }
            }}
            onMouseLeave={(e) => {
              if (userAnswer.trim() && !isLoading) {
                e.target.style.transform = 'translateY(0)';
                e.target.style.boxShadow = '0 4px 12px rgba(255, 107, 107, 0.3)';
              }
            }}
          >
            {isLoading ? '⏳ Analyzing...' : '✅ Submit Answer'}
          </button>
        </div>
      )}

      {/* Micro Feedback */}
      {feedback && (
        <div style={{
          backgroundColor: 'white',
          padding: '24px',
          borderRadius: '12px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          marginBottom: '20px',
          border: '2px solid #28a745'
        }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            marginBottom: '16px'
          }}>
            <span style={{ fontSize: '24px', marginRight: '12px' }}>💡</span>
            <h3 style={{ margin: 0, color: '#28a745', fontSize: '18px', fontWeight: 600 }}>
              Quick Feedback
            </h3>
          </div>

          {/* Good */}
          {feedback.good && (
            <div style={{ marginBottom: '16px' }}>
              <div style={{
                fontSize: '14px',
                fontWeight: 600,
                color: '#28a745',
                marginBottom: '6px'
              }}>
                ✅ Good:
              </div>
              <div style={{
                fontSize: '14px',
                lineHeight: '1.6',
                color: '#212529',
                paddingLeft: '20px'
              }}>
                {feedback.good}
              </div>
            </div>
          )}

          {/* Try */}
          {feedback.try && (
            <div style={{ marginBottom: '16px' }}>
              <div style={{
                fontSize: '14px',
                fontWeight: 600,
                color: '#ffc107',
                marginBottom: '6px'
              }}>
                💡 Try:
              </div>
              <div style={{
                fontSize: '14px',
                lineHeight: '1.6',
                color: '#212529',
                paddingLeft: '20px'
              }}>
                {feedback.try}
              </div>
            </div>
          )}

          {/* Sharper Version */}
          {feedback.sharper && (
            <div style={{
              backgroundColor: '#e7f3ff',
              padding: '16px',
              borderRadius: '8px',
              border: '1px solid #b3d9ff'
            }}>
              <div style={{
                fontSize: '14px',
                fontWeight: 600,
                color: '#007bff',
                marginBottom: '8px'
              }}>
                ⭐ Sharper version:
              </div>
              <div style={{
                fontSize: '14px',
                lineHeight: '1.6',
                color: '#212529',
                whiteSpace: 'pre-wrap'
              }}>
                {feedback.sharper}
              </div>
            </div>
          )}

          {/* Next Button */}
          <button
            onClick={onNext}
            disabled={isLoading}
            style={{
              width: '100%',
              marginTop: '20px',
              padding: '12px 16px',
              background: 'linear-gradient(135deg, #ff6b6b 0%, #ee5a6f 100%)',
              color: 'white',
              border: 'none',
              borderRadius: '10px',
              cursor: 'pointer',
              fontSize: '15px',
              fontWeight: 600,
              transition: 'all 0.2s',
              boxShadow: '0 4px 12px rgba(255, 107, 107, 0.3)'
            }}
            onMouseEnter={(e) => {
              e.target.style.transform = 'translateY(-2px)';
              e.target.style.boxShadow = '0 6px 16px rgba(255, 107, 107, 0.4)';
            }}
            onMouseLeave={(e) => {
              e.target.style.transform = 'translateY(0)';
              e.target.style.boxShadow = '0 4px 12px rgba(255, 107, 107, 0.3)';
            }}
          >
            {questionNumber < totalQuestions ? '➡️ Next Question' : '🎉 Finish Drill'}
          </button>
        </div>
      )}
    </div>
  );
}

export default TrainingZone;

