  },
  {
    id: 'company-fit',
    emoji: '💼',
    label: 'Company fit questions',
    description: 'Why this company? Why this role?'
  },
  {
    id: 'explain-technical',
    emoji: '📐',
    label: 'Explain technical concept simply',
    description: 'Simplify complex topics for non-technical audience'
  },
  {
    id: 'metrics-impact',
