            onFocus={(e) => e.target.style.borderColor = '#ff6b6b'}
            onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
          />
        </div>

        {/* Drill Type Buttons */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: '16px'
        }}>
          {DRILL_TYPES.map(drill => (
            <button
              key={drill.id}
