  // Local state for filters and UI
  const [selectedType, setSelectedType] = useState('All');
  const [selectedTags, setSelectedTags] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [viewMode, setViewMode] = useState('cards'); // 'cards' or 'table'
  const [selectedQuestion, setSelectedQuestion] = useState(null);
  const [showModal, setShowModal] = useState(false);

  // Audio settings - stored locally
  const [bgmEnabled, setBgmEnabled] = useStorage('audio.bgm.enabled', false);
  const [sfxEnabled, setSfxEnabled] = useStorage('audio.sfx.enabled', true);
  const [volume, setVolume] = useStorage('audio.volume', 0.3);

  // Extract all unique tags from questions
  const allTags = useMemo(() => {
    const tagSet = new Set();
    savedQuestions.forEach(q => {
      (q.tags || []).forEach(tag => tagSet.add(tag));
    });
    return Array.from(tagSet).sort();
  }, [savedQuestions]);

  // Filter questions
  const filteredQuestions = useMemo(() => {
    return savedQuestions.filter(q => {
      // Type filter
      if (selectedType !== 'All' && q.interviewType !== selectedType) {
        return false;
      }

      // Tags filter
      if (selectedTags.length > 0) {
        const questionTags = q.tags || [];
        if (!selectedTags.some(tag => questionTags.includes(tag))) {
          return false;
        }
      }

      // Search filter
      if (searchQuery) {
        const query = searchQuery.toLowerCase();
        const matchesQuestion = q.question.toLowerCase().includes(query);
        const matchesAnswer = (q.polishedAnswer || '').toLowerCase().includes(query);
        const matchesOriginal = (q.originalAnswer || '').toLowerCase().includes(query);
        if (!matchesQuestion && !matchesAnswer && !matchesOriginal) {
          return false;
        }
      }

      return true;
    });
  }, [savedQuestions, selectedType, selectedTags, searchQuery]);

  // Update question
  const handleUpdateQuestion = useCallback((updatedQuestion) => {
    setSavedQuestions(prev => 
      prev.map(q => q.id === updatedQuestion.id ? updatedQuestion : q)
    );
    if (sfxEnabled) SoundEffects.save();
  }, [sfxEnabled]);

  // Delete question
  const handleDeleteQuestion = useCallback((id) => {
    if (confirm('Are you sure you want to delete this question?')) {
      setSavedQuestions(prev => prev.filter(q => q.id !== id));
      setShowModal(false);
      if (sfxEnabled) SoundEffects.delete();
    }
  }, [sfxEnabled]);

  // Get daily review questions
  const dailyReviewQuestions = useMemo(() => {
    return savedQuestions
      .filter(q => q.status === 'review')
      .sort(() => Math.random() - 0.5)
      .slice(0, 5);
  }, [savedQuestions]);

  const handleOpenModal = (question) => {
    setSelectedQuestion(question);
    setShowModal(true);
    if (sfxEnabled) SoundEffects.click();
  };

  return (
    <div style={{
      width: '100%',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      backgroundColor: '#f8f9fa',
      fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif',
      overflow: 'hidden'
    }}>
      {/* Audio Manager */}
      <AudioManager bgmEnabled={bgmEnabled} volume={volume} />

      {/* Header */}
      <div style={{
        padding: '20px 24px',
        background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
        borderBottom: '3px solid #e84a5f',
        boxShadow: '0 4px 12px rgba(240, 147, 251, 0.3)'
      }}>
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start'
        }}>
          <div>
            <h2 style={{ 
              margin: 0, 
              fontSize: '24px', 
              color: '#fff', 
              fontWeight: 700,
              display: 'flex',
              alignItems: 'center',
              gap: '12px'
            }}>
              <span style={{ fontSize: '28px' }}>{'\u{1F4DA}'}</span>
              <span>Question Library</span>
            </h2>
            <div style={{
              display: 'flex',
              justifyContent: 'space-between',
              alignItems: 'center',
              marginTop: '8px',
              marginLeft: '40px'
            }}>
              <p style={{ 
                margin: 0, 
                fontSize: '13px', 
                color: 'rgba(255,255,255,0.9)',
                fontWeight: 400
              }}>
                {savedQuestions.length} saved questions • {dailyReviewQuestions.length} ready for review
              </p>
            </div>
          </div>

          {/* Audio Controls */}
          <div style={{
            display: 'flex',
            gap: '8px',
            alignItems: 'center'
          }}>
            <button
              onClick={() => {
                setBgmEnabled(!bgmEnabled);
                if (sfxEnabled) SoundEffects.click();
              }}
              style={{
                padding: '8px 12px',
                fontSize: '12px',
                fontWeight: 600,
                backgroundColor: bgmEnabled ? 'rgba(255,255,255,0.3)' : 'rgba(0,0,0,0.2)',
                color: 'white',
                border: bgmEnabled ? '2px solid rgba(255,255,255,0.5)' : '2px solid transparent',
                borderRadius: '8px',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: '6px',
                transition: 'all 0.2s'
              }}
              title={bgmEnabled ? 'Disable background music' : 'Enable background music'}
            >
              {bgmEnabled ? '🎵' : '🔇'} BGM
            </button>
            <button
              onClick={() => {
                setSfxEnabled(!sfxEnabled);
                if (!sfxEnabled) SoundEffects.click();
              }}
              style={{
                padding: '8px 12px',
                fontSize: '12px',
                fontWeight: 600,
                backgroundColor: sfxEnabled ? 'rgba(255,255,255,0.3)' : 'rgba(0,0,0,0.2)',
                color: 'white',
                border: sfxEnabled ? '2px solid rgba(255,255,255,0.5)' : '2px solid transparent',
                borderRadius: '8px',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: '6px',
                transition: 'all 0.2s'
              }}
              title={sfxEnabled ? 'Disable sound effects' : 'Enable sound effects'}
            >
              {sfxEnabled ? '🔊' : '🔈'} SFX
            </button>
          </div>
        </div>
      </div>

      {/* Filter Bar */}
      <FilterBar
        selectedType={selectedType}
        setSelectedType={setSelectedType}
        selectedTags={selectedTags}
        setSelectedTags={setSelectedTags}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
        viewMode={viewMode}
        setViewMode={setViewMode}
        allTags={allTags}
        filteredCount={filteredQuestions.length}
        totalCount={savedQuestions.length}
      />

      {/* Content Area */}
      <div style={{
        flex: 1,
        overflow: 'auto',
        padding: '20px'
      }}>
        {savedQuestions.length === 0 ? (
          <div style={{
            textAlign: 'center',
            padding: '60px 20px',
            color: '#6c757d'
          }}>
            <div style={{ fontSize: '64px', marginBottom: '20px' }}>??</div>
            <h3 style={{ fontSize: '20px', marginBottom: '10px', color: '#495057' }}>
              No saved questions yet
            </h3>
            <p style={{ fontSize: '14px', maxWidth: '400px', margin: '0 auto' }}>
              Use the Interview Simulator to practice questions and save them here for future review.
            </p>
          </div>
        ) : filteredQuestions.length === 0 ? (
          <div style={{
            textAlign: 'center',
            padding: '60px 20px',
            color: '#6c757d'
          }}>
            <div style={{ fontSize: '64px', marginBottom: '20px' }}>??</div>
            <h3 style={{ fontSize: '20px', marginBottom: '10px', color: '#495057' }}>
              No questions match your filters
            </h3>
            <p style={{ fontSize: '14px' }}>
              Try adjusting your search or filters
            </p>
          </div>
        ) : (
          <div style={{
            display: 'grid',
            gridTemplateColumns: viewMode === 'cards' 
              ? 'repeat(auto-fill, minmax(350px, 1fr))' 
              : '1fr',
            gap: '20px',
            maxWidth: '1400px',
            margin: '0 auto'
          }}>
            {filteredQuestions.map(question => (
              <QuestionCard
                key={question.id}
                question={question}
                viewMode={viewMode}
                onOpen={() => handleOpenModal(question)}
                onUpdate={handleUpdateQuestion}
                onDelete={handleDeleteQuestion}
                sfxEnabled={sfxEnabled}
              />
            ))}
          </div>
        )}
      </div>

      {/* Modal */}
      {showModal && selectedQuestion && (
        <QuestionModal
          question={selectedQuestion}
          onClose={() => setShowModal(false)}
          onUpdate={handleUpdateQuestion}
          onDelete={handleDeleteQuestion}
          sfxEnabled={sfxEnabled}
        />
      )}
    </div>
  );
}

export default QuestionLibrary;

