import React, { useState } from 'react';
import { SoundEffects } from './AudioManager.jsx';

function QuestionModal({ question, onClose, onUpdate, onDelete, sfxEnabled }) {
  const [notes, setNotes] = useState(question.notes || '');
  const [tags, setTags] = useState(question.tags || []);
  const [newTag, setNewTag] = useState('');
  const [showTagInput, setShowTagInput] = useState(false);
  const [activeTab, setActiveTab] = useState('polished'); // 'polished' or 'original'

  const getScoreColor = (score) => {
    if (score >= 8) return '#28a745';
    if (score >= 6) return '#ffc107';
    return '#dc3545';
  };

  const formatDate = (timestamp) => {
    const date = new Date(timestamp);
    return date.toLocaleDateString('en-US', { 
      month: 'long', 
      day: 'numeric', 
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const handleSave = () => {
    onUpdate({
      ...question,
      notes,
      tags
    });
    onClose();
    if (sfxEnabled) SoundEffects.save();
  };

  const handleToggleStatus = () => {
    const newStatus = question.status === 'mastered' ? 'review' : 'mastered';
    onUpdate({ ...question, status: newStatus });
    if (sfxEnabled) {
      if (newStatus === 'mastered') {
        SoundEffects.success();
      } else {
        SoundEffects.review();
      }
    }
  };

  const handleAddTag = () => {
    if (newTag.trim() && !tags.includes(newTag.trim())) {
      setTags([...tags, newTag.trim()]);
      setNewTag('');
      setShowTagInput(false);
      if (sfxEnabled) SoundEffects.notification();
    }
  };

  const handleRemoveTag = (tagToRemove) => {
    setTags(tags.filter(t => t !== tagToRemove));
    if (sfxEnabled) SoundEffects.click();
  };

  const handleExportPDF = async () => {
    alert('Export to PDF feature coming soon!');
  };

  return (
    <div
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'rgba(0,0,0,0.5)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 1000,
        padding: '20px'
      }}
      onClick={onClose}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        style={{
          backgroundColor: 'white',
          borderRadius: '20px',
          maxWidth: '900px',
          width: '100%',
          maxHeight: '90vh',
          overflow: 'auto',
          boxShadow: '0 20px 60px rgba(0,0,0,0.3)'
        }}
      >
        {/* Header */}
        <div style={{
          padding: '24px 32px',
          background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
          borderRadius: '20px 20px 0 0',
          position: 'sticky',
          top: 0,
          zIndex: 10
        }}>
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'flex-start',
            marginBottom: '12px'
          }}>
            <div style={{
              display: 'inline-block',
              padding: '6px 16px',
              fontSize: '12px',
              fontWeight: 600,
              backgroundColor: 'rgba(255,255,255,0.3)',
              color: 'white',
              borderRadius: '16px'
            }}>
              {question.interviewType} • {question.role}
            </div>
            <button
              onClick={() => {
                onClose();
                if (sfxEnabled) SoundEffects.click();
              }}
              style={{
                padding: '8px 12px',
                backgroundColor: 'rgba(255,255,255,0.2)',
                color: 'white',
                border: 'none',
                borderRadius: '10px',
                cursor: 'pointer',
                fontSize: '18px',
                fontWeight: 600
              }}
            >
              ✕
            </button>
          </div>
          <h2 style={{
            margin: 0,
            fontSize: '20px',
            color: 'white',
            fontWeight: 600,
            lineHeight: '1.4'
          }}>
            {question.question}
          </h2>
          <div style={{
            marginTop: '12px',
            display: 'flex',
            gap: '16px',
            alignItems: 'center'
          }}>
            <div style={{
              fontSize: '24px',
              fontWeight: 700,
              color: 'white'
            }}>
              Score: {question.score}/10
            </div>
            <div style={{
              fontSize: '13px',
              color: 'rgba(255,255,255,0.9)'
            }}>
              {formatDate(question.timestamp)}
            </div>
          </div>
        </div>

        {/* Content */}
        <div style={{ padding: '32px' }}>
          {/* Answer Tabs */}
          <div style={{ marginBottom: '24px' }}>
            <div style={{
              display: 'flex',
              gap: '8px',
              marginBottom: '16px',
              borderBottom: '2px solid #f1f3f5'
            }}>
              <button
                onClick={() => {
                  setActiveTab('polished');
                  if (sfxEnabled) SoundEffects.click();
                }}
                style={{
                  padding: '12px 24px',
                  fontSize: '14px',
                  fontWeight: 600,
                  backgroundColor: 'transparent',
                  color: activeTab === 'polished' ? '#f093fb' : '#6c757d',
                  border: 'none',
                  borderBottom: activeTab === 'polished' ? '3px solid #f093fb' : '3px solid transparent',
                  cursor: 'pointer',
                  marginBottom: '-2px'
                }}
              >
                ⭐ Polished Answer
              </button>
              <button
                onClick={() => {
                  setActiveTab('original');
                  if (sfxEnabled) SoundEffects.click();
                }}
                style={{
                  padding: '12px 24px',
                  fontSize: '14px',
                  fontWeight: 600,
                  backgroundColor: 'transparent',
                  color: activeTab === 'original' ? '#f093fb' : '#6c757d',
                  border: 'none',
                  borderBottom: activeTab === 'original' ? '3px solid #f093fb' : '3px solid transparent',
                  cursor: 'pointer',
                  marginBottom: '-2px'
                }}
              >
                📝 Original Answer
              </button>
            </div>

            <div style={{
              backgroundColor: '#f8f9fa',
              padding: '20px',
              borderRadius: '12px',
              fontSize: '14px',
              lineHeight: '1.8',
              color: '#212529',
              whiteSpace: 'pre-wrap'
            }}>
              {activeTab === 'polished' 
                ? (question.polishedAnswer || 'No polished answer available')
                : (question.originalAnswer || 'No original answer available')
              }
            </div>
          </div>

          {/* Feedback */}
          {(question.strengths?.length > 0 || question.improvements?.length > 0) && (
            <div style={{
              marginBottom: '24px',
              padding: '20px',
              backgroundColor: '#f8f9fa',
              borderRadius: '12px'
            }}>
              <h4 style={{
                margin: '0 0 16px 0',
                fontSize: '16px',
                fontWeight: 600,
                color: '#212529'
              }}>
                📊 Feedback Summary
              </h4>

              {question.strengths?.length > 0 && (
                <div style={{ marginBottom: '16px' }}>
                  <div style={{
                    fontSize: '14px',
                    fontWeight: 600,
                    color: '#28a745',
                    marginBottom: '8px'
                  }}>
                    ✅ Strengths
                  </div>
                  <ul style={{ margin: 0, paddingLeft: '20px' }}>
                    {question.strengths.map((strength, idx) => (
                      <li key={idx} style={{
                        fontSize: '13px',
                        color: '#495057',
                        marginBottom: '4px',
                        lineHeight: '1.6'
                      }}>
                        {strength}
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              {question.improvements?.length > 0 && (
                <div>
                  <div style={{
                    fontSize: '14px',
                    fontWeight: 600,
                    color: '#dc3545',
                    marginBottom: '8px'
                  }}>
                    🛠️ Areas for Improvement
                  </div>
                  <ul style={{ margin: 0, paddingLeft: '20px' }}>
                    {question.improvements.map((improvement, idx) => (
                      <li key={idx} style={{
                        fontSize: '13px',
                        color: '#495057',
                        marginBottom: '4px',
                        lineHeight: '1.6'
                      }}>
                        {improvement}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          )}

          {/* Tags */}
          <div style={{ marginBottom: '24px' }}>
            <label style={{
              display: 'block',
              fontSize: '14px',
              fontWeight: 600,
              color: '#495057',
              marginBottom: '12px'
            }}>
              🏷️ Tags
            </label>
            <div style={{
              display: 'flex',
              flexWrap: 'wrap',
              gap: '8px',
              marginBottom: '12px'
            }}>
              {tags.map((tag, idx) => (
                <span
                  key={idx}
                  style={{
                    padding: '6px 12px',
                    fontSize: '13px',
                    backgroundColor: '#f093fb',
                    color: 'white',
                    borderRadius: '16px',
                    fontWeight: 500,
                    display: 'flex',
                    alignItems: 'center',
                    gap: '6px'
                  }}
                >
                  {tag}
                  <button
                    onClick={() => handleRemoveTag(tag)}
                    style={{
                      backgroundColor: 'transparent',
                      border: 'none',
                      color: 'white',
                      cursor: 'pointer',
                      padding: 0,
                      fontSize: '14px'
                    }}
                  >
                    ✕
                  </button>
                </span>
              ))}
              {!showTagInput ? (
              <button
                onClick={() => {
                  setShowTagInput(true);
                  if (sfxEnabled) SoundEffects.click();
                }}
                  style={{
                    padding: '6px 12px',
                    fontSize: '13px',
                    backgroundColor: '#e9ecef',
                    color: '#6c757d',
                    border: 'none',
                    borderRadius: '16px',
                    cursor: 'pointer',
                    fontWeight: 500
                  }}
                >
                  + Add tag
                </button>
              ) : (
                <div style={{ display: 'flex', gap: '6px' }}>
                  <input
                    type="text"
                    value={newTag}
                    onChange={(e) => setNewTag(e.target.value)}
                    onKeyPress={(e) => e.key === 'Enter' && handleAddTag()}
                    placeholder="Tag name..."
                    style={{
                      padding: '6px 12px',
                      fontSize: '13px',
                      border: '2px solid #f093fb',
                      borderRadius: '16px',
                      outline: 'none'
                    }}
                    autoFocus
                  />
                  <button
                    onClick={handleAddTag}
                    style={{
                      padding: '6px 12px',
                      backgroundColor: '#f093fb',
                      color: 'white',
                      border: 'none',
                      borderRadius: '16px',
                      cursor: 'pointer'
                    }}
                  >
                    ✓
                  </button>
                  <button
                    onClick={() => {
                      setShowTagInput(false);
                      setNewTag('');
                    }}
                    style={{
                      padding: '6px 12px',
                      backgroundColor: '#6c757d',
                      color: 'white',
                      border: 'none',
                      borderRadius: '16px',
                      cursor: 'pointer'
                    }}
                  >
                    ✕
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Notes */}
          <div style={{ marginBottom: '24px' }}>
            <label style={{
              display: 'block',
              fontSize: '14px',
              fontWeight: 600,
              color: '#495057',
              marginBottom: '12px'
            }}>
              📝 My Notes
            </label>
            <textarea
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder="Add your personal notes, reflections, or reminders..."
              rows={4}
              style={{
                width: '100%',
                padding: '12px',
                fontSize: '14px',
                border: '2px solid #e9ecef',
                borderRadius: '10px',
                fontFamily: 'inherit',
                resize: 'vertical',
                lineHeight: '1.6',
                outline: 'none'
              }}
              onFocus={(e) => e.target.style.borderColor = '#f093fb'}
              onBlur={(e) => e.target.style.borderColor = '#e9ecef'}
            />
          </div>

          {/* Actions */}
          <div style={{
            display: 'flex',
            gap: '12px',
            justifyContent: 'space-between',
            paddingTop: '20px',
            borderTop: '2px solid #f1f3f5'
          }}>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button
                onClick={handleToggleStatus}
                style={{
                  padding: '12px 24px',
                  fontSize: '14px',
                  fontWeight: 600,
                  backgroundColor: question.status === 'mastered' ? '#28a745' : '#ffc107',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  cursor: 'pointer',
                  transition: 'all 0.2s'
                }}
              >
                {question.status === 'mastered' ? '✓ Mastered' : '📝 Mark as Review'}
              </button>
              <button
                onClick={handleExportPDF}
                style={{
                  padding: '12px 24px',
                  fontSize: '14px',
                  fontWeight: 600,
                  backgroundColor: '#17a2b8',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  cursor: 'pointer'
                }}
              >
                📄 Export PDF
              </button>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button
                onClick={() => {
                  onDelete(question.id);
                  if (sfxEnabled) SoundEffects.delete();
                }}
                style={{
                  padding: '12px 24px',
                  fontSize: '14px',
                  fontWeight: 600,
                  backgroundColor: '#dc3545',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  cursor: 'pointer'
                }}
              >
                🗑️ Delete
              </button>
              <button
                onClick={handleSave}
                style={{
                  padding: '12px 32px',
                  fontSize: '14px',
                  fontWeight: 600,
                  background: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  cursor: 'pointer',
                  boxShadow: '0 4px 12px rgba(240, 147, 251, 0.4)'
                }}
              >
                💾 Save Changes
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default QuestionModal;
